package com.practice.visual.controller;
import com.practice.common.*;import com.practice.visual.entity.*;import com.practice.visual.dao.*;import com.practice.visual.service.*;import org.springframework.data.jpa.repository.JpaRepository;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/screens") class ScreenController extends CrudController<DashboardScreen>{ final ScreenService screens; ScreenController(DashboardScreenDao r, CrudService<DashboardScreen> c, ScreenService screens){super(r,c);this.screens=screens;} @PostMapping("/{id}/publish") ApiResponse<DashboardScreen> pub(@PathVariable Long id){return ApiResponse.ok(screens.publish(id));} }
@RestController @RequestMapping("/api/video-devices") class VideoDeviceController { final VideoDeviceDao dao; final CrudService<VideoDevice> service; VideoDeviceController(VideoDeviceDao dao, CrudService<VideoDevice> service){this.dao=dao;this.service=service;} @GetMapping ApiResponse<List<VideoDevice>> list(@RequestParam(required=false) String keyword){return ApiResponse.ok(service.list(dao,keyword));} @GetMapping("/{id}") ApiResponse<VideoDevice> get(@PathVariable Long id){return ApiResponse.ok(service.get(dao,id));} @PostMapping ApiResponse<Object> create(jakarta.servlet.http.HttpServletResponse response){response.setStatus(405);return new ApiResponse<>(405,"Method Not Allowed",null);} @PutMapping("/{id}") ApiResponse<Object> update(@PathVariable Long id,jakarta.servlet.http.HttpServletResponse response){response.setStatus(405);return new ApiResponse<>(405,"Method Not Allowed",null);} @DeleteMapping("/{id}") ApiResponse<Object> delete(@PathVariable Long id,jakarta.servlet.http.HttpServletResponse response){response.setStatus(405);return new ApiResponse<>(405,"Method Not Allowed",null);} @PostMapping("/{id}/toggle") ApiResponse<Object> toggle(@PathVariable Long id,jakarta.servlet.http.HttpServletResponse response){response.setStatus(405);return new ApiResponse<>(405,"Method Not Allowed",null);} }
@RestController @RequestMapping("/api/video-streams") class VideoStreamController extends CrudController<VideoStreamProxy>{ VideoStreamController(VideoStreamProxyDao r, CrudService<VideoStreamProxy> c){super(r,c);} }
@RestController @RequestMapping("/api/video-alarm-tasks") class VideoAlarmTaskController extends CrudController<VideoAlarmTask>{ VideoAlarmTaskController(VideoAlarmTaskDao r, CrudService<VideoAlarmTask> c){super(r,c);} }
abstract class CrudController<T extends BaseEntity>{ final JpaRepository<T,Long> dao; final CrudService<T> service; CrudController(JpaRepository<T,Long> dao,CrudService<T> service){this.dao=dao;this.service=service;} @GetMapping ApiResponse<List<T>> list(@RequestParam(required=false) String keyword){return ApiResponse.ok(service.list(dao,keyword));} @GetMapping("/{id}") ApiResponse<T> get(@PathVariable Long id){return ApiResponse.ok(service.get(dao,id));} @PostMapping ApiResponse<T> create(@RequestBody T body){return ApiResponse.ok(service.create(dao,body));} @PutMapping("/{id}") ApiResponse<T> update(@PathVariable Long id,@RequestBody T body){return ApiResponse.ok(service.update(dao,id,body));} @DeleteMapping("/{id}") ApiResponse<Boolean> delete(@PathVariable Long id){return ApiResponse.ok(service.delete(dao,id));} @PostMapping("/{id}/toggle") ApiResponse<T> toggle(@PathVariable Long id){return ApiResponse.ok(service.toggle(dao,id));} }
